RETURNS boolean
LANGUAGE plpgsql
AS $$
DECLARE
  v_balance int;
BEGIN
  UPDATE credit_wallets
  SET balance = balance - p_amount
  WHERE owner_id = p_owner_id AND balance >= p_amount
  RETURNING balance INTO v_balance;

  RETURN FOUND;
END;
$$;
