class TopAmbassadorsPage extends StatefulWidget {
  @override
  State<TopAmbassadorsPage> createState() => _TopAmbassadorsPageState();
}

class _TopAmbassadorsPageState extends State<TopAmbassadorsPage> {
  final _supabase = Supabase.instance.client;
  bool _isLoading = true;
  List<AmbassadorEntry> _leaderboard = [];

  @override
  void initState() {
    super.initState();
    _loadLeaderboard();
  }

  Future<void> _loadLeaderboard() async {
    setState(() {
      _isLoading = true;
    });

    try {
      final response = await _supabase
          .from('referral_profit_sharing')
          .select('''
            referrer_id,
            profiles!referral_profit_sharing_referrer_id_fkey (
              display_name,
              avatar_url
            ),
            commission_amount
          ''');

      // Aggregate by referrer
      final Map<String, AmbassadorEntry> aggregated = {};

      for (final row in response) {
        final referrerId = row['referrer_id'] as String;
        final commission = (row['commission_amount'] as num).toDouble();

        if (!aggregated.containsKey(referrerId)) {
          aggregated[referrerId] = AmbassadorEntry(
            userId: referrerId,
            displayName: row['profiles']['display_name'] ?? 'Anonymous',
            avatarUrl: row['profiles']['avatar_url'],
            totalReferrals: 0,
            totalCommission: 0,
          );
        }

        aggregated[referrerId] = aggregated[referrerId]!.copyWith(
          totalReferrals: aggregated[referrerId]!.totalReferrals + 1,
          totalCommission: aggregated[referrerId]!.totalCommission + commission,
        );
      }

      // Sort by referral count and take top 10
      final sorted = aggregated.values.toList()
        ..sort((a, b) => b.totalReferrals.compareTo(a.totalReferrals));

      setState(() {
        _leaderboard = sorted.take(10).toList();
        _isLoading = false;
      });
    } catch (e) {
      debugPrint('Error loading leaderboard: $e');
      setState(() {
        _isLoading = false;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Top Ambassadors')),
      body: _isLoading
          ? const Center(child: CircularProgressIndicator())
          : ListView.builder(
              padding: const EdgeInsets.all(16),
              itemCount: _leaderboard.length,
              itemBuilder: (context, index) {
                final entry = _leaderboard[index];
                return AmbassadorLeaderboardTile(
                  rank: index + 1,
                  entry: entry,
                );
              },
            ),
    );
  }
}

