  }

  Future<void> _approveApplication(String applicationId, String userId) async {
    try {
      await _supabase.functions.invoke(
        'approve_ambassador_application',
        body: {
          'application_id': applicationId,
          'user_id': userId,
        },
      );

      // Reload list
      await _loadApplications();

      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Application approved')),
      );
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Failed to approve: $e')),
      );
    }
  }

  Future<void> _rejectApplication(String applicationId) async {
    try {
      await _supabase
          .from('ambassador_applications')
          .update({'status': 'rejected'})
          .eq('id', applicationId);

      // Send notification
      final application = _applications.firstWhere((app) => app.id == applicationId);
      await _supabase.from('notifications').insert({
        'user_id': application.userId,
        'title': 'Ambassador Application',
        'message': 'Your application has been reviewed. Unfortunately, it was not approved at this time.',
        'type': 'ambassador',
      });

      await _loadApplications();

      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text('Application rejected')),
      );
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Failed to reject: $e')),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Ambassador Applications')),
      body: _isLoading
          ? const Center(child: CircularProgressIndicator())
          : _applications.isEmpty
              ? const Center(child: Text('No pending applications'))
              : ListView.builder(
                  padding: const EdgeInsets.all(16),
                  itemCount: _applications.length,
                  itemBuilder: (context, index) {
                    final application = _applications[index];
                    return _buildApplicationCard(application);
                  },
                ),
    );
  }

  Widget _buildApplicationCard(AmbassadorApplication application) {
    return Card(
      margin: const EdgeInsets.only(bottom: 16),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                CircleAvatar(
                  child: Text(application.displayName[0].toUpperCase()),
                ),
                const SizedBox(width: 12),
                Expanded(
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        application.displayName,
                        style: Theme.of(context).textTheme.titleMedium,
                      ),
                      Text(
                        application.email,
                        style: Theme.of(context).textTheme.bodySmall,
                      ),
                    ],
                  ),
                ),
                Text(
                  _formatDate(application.createdAt),
                  style: Theme.of(context).textTheme.bodySmall,
                ),
              ],
            ),
            const SizedBox(height: 12),
            Text('Reason: ${application.reason}'),
            if (application.platform.isNotEmpty) ...[
              const SizedBox(height: 8),
              Wrap(
                spacing: 8,
                children: application.platform
                    .map((p) => Chip(label: Text(p)))
                    .toList(),
              ),
            ],
            const SizedBox(height: 16),
            Row(
              children: [
                Expanded(
                  child: ElevatedButton(
                    onPressed: () => _approveApplication(application.id, application.userId),
                    child: const Text('Approve'),
                  ),
                ),
                const SizedBox(width: 12),
                Expanded(
                  child: OutlinedButton(
                    onPressed: () => _rejectApplication(application.id),
                    child: const Text('Reject'),
                  ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }

  String _formatDate(DateTime date) {
    return DateFormat('MMM d, y').format(date);
  }
}

class AmbassadorApplication {
  final String id;
  final String userId;
  final String displayName;
  final String email;
  final String reason;
  final List<String> platform;
  final DateTime createdAt;

  factory AmbassadorApplication.fromJson(Map<String, dynamic> json) {
    final profile = json['profiles'] as Map<String, dynamic>? ?? {};
    return AmbassadorApplication(
      id: json['id'] as String,
      userId: json['user_id'] as String,
      displayName: profile['display_name'] as String? ?? 'Unknown',
      email: profile['email'] as String? ?? 'Unknown',
      reason: json['reason'] as String? ?? '',
      platform: (json['platform'] as List?)?.cast<String>() ?? [],
      createdAt: DateTime.parse(json['created_at'] as String),
