## R05 - Add Payout Cron Monitoring

**Time**: 2 hr | **Priority**: P2

**File**: `lib/src/features/admin/payout_monitoring_page.dart` (new)

**Implementation**:
```dart
class PayoutMonitoringPage extends StatefulWidget {
  @override
  State<PayoutMonitoringPage> createState() => _PayoutMonitoringPageState();
}

class _PayoutMonitoringPageState extends State<PayoutMonitoringPage> {
  final _supabase = Supabase.instance.client;
  bool _isLoading = true;
  PayoutStats? _stats;

  @override
  void initState() {
    super.initState();
    _loadStats();
  }

  Future<void> _loadStats() async {
    setState(() {
      _isLoading = true;
    });

    try {
      // Get last successful run from audit_events
      final auditResponse = await _supabase
          .from('audit_events')
          .select('created_at, metadata')
          .eq('action', 'payout_cron_run')
          .order('created_at', ascending: false)
          .limit(1)
          .maybeSingle();

      // Get payout summary
      final payoutResponse = await _supabase
          .from('referral_ledger')
          .select('amount, status')
          .gte('created_at', DateTime.now().subtract(const Duration(days: 30)).toIso8601String());

      int totalPaidOut = 0;
      int failedCount = 0;

      for (final payout in payoutResponse) {
        if (payout['status'] == 'paid') {
          totalPaidOut += (payout['amount'] as num).toInt();
        } else if (payout['status'] == 'failed') {
          failedCount++;
        }
      }

      setState(() {
        _stats = PayoutStats(
          lastRun: auditResponse != null
              ? DateTime.parse(auditResponse['created_at'])
              : null,
          lastRunPayouts: auditResponse?['metadata']?['payouts_processed'] ?? 0,
          totalPaidOut: totalPaidOut,
          failedPayouts: failedCount,
        );
        _isLoading = false;
      });
    } catch (e) {
      debugPrint('Error loading payout stats: $e');
      setState(() {
        _isLoading = false;
      });
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Payout Monitoring')),
      body: _isLoading
          ? const Center(child: CircularProgressIndicator())
          : SingleChildScrollView(
              padding: const EdgeInsets.all(16),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    'Payout Status',
                    style: Theme.of(context).textTheme.headlineSmall,
                  ),
                  const SizedBox(height: 16),

                  // Last run info
                  Card(
                    child: Padding(
                      padding: const EdgeInsets.all(16),
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(
                            'Last Cron Run',
                            style: Theme.of(context).textTheme.titleMedium,
                          ),
                          const SizedBox(height: 8),
                          Text(
                            _stats?.lastRun != null
                                ? DateFormat('MMM d, y HH:mm').format(_stats!.lastRun!)
                                : 'Never',
                          ),
                          if (_stats?.lastRun != null)
                            Text(
                              '${_stats!.lastRunPayouts} payouts processed',
                              style: Theme.of(context).textTheme.bodySmall,
                            ),
                        ],
                      ),
                    ),
                  ),

                  const SizedBox(height: 16),

                  // Stats row
                  Row(
                    children: [
                      Expanded(
                        child: _buildStatCard(
                          'Total Paid (30d)',
                          '\$${(_stats?.totalPaidOut ?? 0) / 100}',
                          Icons.payments,
                          Colors.green,
                        ),
                      ),
                      const SizedBox(width: 16),
                      Expanded(
                        child: _buildStatCard(
                          'Failed Payouts',
                          '${_stats?.failedPayouts ?? 0}',
                          Icons.error,
                          Colors.red,
                        ),
                      ),
                    ],
                  ),

                  if (_stats?.failedPayouts ?? 0 > 0) ...[
                    const SizedBox(height: 16),
                    Card(
                      color: Colors.red.shade50,
                      child: Padding(
                        padding: const EdgeInsets.all(16),
                        child: Row(
                          children: [
                            Icon(Icons.warning, color: Colors.red.shade700),
                            const SizedBox(width: 12),
                            Expanded(
                              child: Text(
                                '${_stats!.failedPayouts} payouts failed. Review required.',
                                style: TextStyle(color: Colors.red.shade900),
                              ),
                            ),
                          ],
                        ),
                      ),
                    ),
                  ],
                ],
              ),
            ),
    );
  }

  Widget _buildStatCard(String title, String value, IconData icon, Color color) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Icon(icon, color: color, size: 32),
            const SizedBox(height: 8),
            Text(
              title,
              style: Theme.of(context).textTheme.bodySmall,
            ),
            const SizedBox(height: 4),
            Text(
              value,
              style: Theme.of(context).textTheme.headlineSmall,
            ),
          ],
        ),
      ),
    );
  }
}

class PayoutStats {
  final DateTime? lastRun;
  final int lastRunPayouts;
  final int totalPaidOut;
  final int failedPayouts;

  PayoutStats({
    required this.lastRun,
    required this.lastRunPayouts,
    required this.totalPaidOut,
    required this.failedPayouts,
  });
}
```

